package com.samudhra.certificates.entity;
import jakarta.persistence.*;
@Entity @Table(name="template_elements", indexes=@Index(columnList="template_id")) public class TemplateElement extends BaseEntity {
  @ManyToOne(fetch=FetchType.LAZY, optional=false) private Template template; @Column(nullable=false) private String elementId; @Column(nullable=false) private String type; private String role; @Lob @Column(columnDefinition="LONGTEXT") private String content; @Lob @Column(columnDefinition="LONGTEXT") private String assetUrl; private Double x; private Double y; private Double width; private Double height; private Double scaleX=1d; private Double scaleY=1d; private Double angle=0d; private Double opacity=1d; private Integer zIndex=1; private boolean locked; private boolean visible=true; @Lob @Column(columnDefinition="LONGTEXT") private String styleJson;
  public Template getTemplate(){return template;} public void setTemplate(Template v){template=v;} public String getElementId(){return elementId;} public void setElementId(String v){elementId=v;} public String getType(){return type;} public void setType(String v){type=v;} public String getRole(){return role;} public void setRole(String v){role=v;} public String getContent(){return content;} public void setContent(String v){content=v;} public String getAssetUrl(){return assetUrl;} public void setAssetUrl(String v){assetUrl=v;} public Double getX(){return x;} public void setX(Double v){x=v;} public Double getY(){return y;} public void setY(Double v){y=v;} public Double getWidth(){return width;} public void setWidth(Double v){width=v;} public Double getHeight(){return height;} public void setHeight(Double v){height=v;} public Double getScaleX(){return scaleX;} public void setScaleX(Double v){scaleX=v;} public Double getScaleY(){return scaleY;} public void setScaleY(Double v){scaleY=v;} public Double getAngle(){return angle;} public void setAngle(Double v){angle=v;} public Double getOpacity(){return opacity;} public void setOpacity(Double v){opacity=v;} public Integer getZIndex(){return zIndex;} public void setZIndex(Integer v){zIndex=v;} public boolean isLocked(){return locked;} public void setLocked(boolean v){locked=v;} public boolean isVisible(){return visible;} public void setVisible(boolean v){visible=v;} public String getStyleJson(){return styleJson;} public void setStyleJson(String v){styleJson=v;}
}
